export type ExtractResult = { text: string; format: string; truncated?: boolean };

const MAX_CHARS = 50000;

export async function extractFile(filename: string, buffer: Buffer): Promise<ExtractResult> {
  const ext = (filename.split(".").pop() ?? "").toLowerCase();

  if (["txt", "md", "json", "csv", "tsv", "log", "yaml", "yml"].includes(ext)) {
    let text = buffer.toString("utf-8");
    if (text.length > MAX_CHARS) {
      text = text.slice(0, MAX_CHARS) + "\n…[truncado]";
      return { text, format: ext, truncated: true };
    }
    return { text, format: ext };
  }

  if (ext === "pdf") {
    try {
      const { extractText, getDocumentProxy } = await import("unpdf");
      const uint8 = new Uint8Array(buffer);
      const pdf = await getDocumentProxy(uint8);
      const result = await extractText(pdf, { mergePages: true });
      const raw = Array.isArray(result.text) ? result.text.join("\n") : (result.text ?? "");
      let text = raw.replace(/�/g, "").trim();
      if (text.length === 0) {
        return {
          text: `[PDF sin texto extraíble — ${result.totalPages ?? "?"} páginas. Posiblemente escaneado o sólo imágenes; necesitaría OCR.]`,
          format: "pdf",
        };
      }
      if (text.length > MAX_CHARS) {
        text = text.slice(0, MAX_CHARS) + "\n…[truncado]";
        return { text, format: "pdf", truncated: true };
      }
      return { text, format: "pdf" };
    } catch (e: any) {
      return { text: `[Error extrayendo PDF: ${e.message}]`, format: "pdf" };
    }
  }

  if (ext === "docx") {
    try {
      const mammoth = await import("mammoth");
      const result = await mammoth.extractRawText({ buffer });
      let text = result.value ?? "";
      if (text.length > MAX_CHARS) {
        text = text.slice(0, MAX_CHARS) + "\n…[truncado]";
        return { text, format: "docx", truncated: true };
      }
      return { text, format: "docx" };
    } catch (e: any) {
      return { text: `[Error extrayendo DOCX: ${e.message}]`, format: "docx" };
    }
  }

  return {
    text: `[Archivo ${filename} (${ext}) — formato no extraíble. Tamaño: ${buffer.length} bytes]`,
    format: ext || "unknown",
  };
}
